export type MaterialIconName = keyof typeof ICONS;

/**
 * Inlined Material Icon Theme file icon (no runtime network, no extra deps).
 * Unknown `name` falls back to the generic document icon. Size the icon via the
 * wrapper `className` (e.g. `size-9`); the inner SVG stretches to fill it.
 */
export const MaterialFileIcon: FC<{ name: string; className?: string }> = ({
  name,
  className,
}) => {
  const svg = ICONS[name] ?? ICONS.document ?? "";
  return (
    <span
      className={className}
      aria-hidden
      // eslint-disable-next-line react/no-danger -- trusted static SVG inlined at build time
      dangerouslySetInnerHTML={{ __html: svg }}
    />
  );
};
